eval("class ProductTile extends HTMLElement {\r\n  constructor(){\r\n    super();\r\n     /* POPUP FOR RECHARGE PRODUCTS */\r\n    const popupAtc = (() => {\r\n      const elements = {\r\n        popups: document.querySelectorAll('.product_popup'),\r\n        html: document.querySelector('html'),\r\n        activate_buttons: document.querySelectorAll('.activate_popup'),\r\n        page_overlay: document.querySelector('.page-overlay'),\r\n        product_page_form: document.querySelector('.product-page-form'),\r\n        popup_toggle: document.querySelectorAll('.popup_toggle')\r\n      };   \r\n      const init = () => {\r\n        addEventListeners();\r\n      }\r\n      const addEventListeners = () => {\r\n        /* show and hide popup */\r\n        setTimeout(() => {\r\n          const activate_buttons = document.querySelectorAll('.activate_popup');\r\n          activate_buttons.forEach(button => {\r\n            button.addEventListener('click', () => {\r\n              const productTileFindPopups = button.closest('[data-product-tile]').querySelectorAll('.product_popup');\r\n              let popups;\r\n              if(productTileFindPopups.length > 0){\r\n                popups = productTileFindPopups;\r\n              } else {\r\n                popups = button.closest('.container').querySelectorAll('.product_popup');\r\n              }\r\n              const dataTitle = button.closest('.content_container').dataset.title;\r\n              popups.forEach(popup => {\r\n                elements.page_overlay.addEventListener('click', () => {\r\n                  closePopup(popup);\r\n                });\r\n                let popup_cross = popup.querySelector('.cross');\r\n                if(popup.dataset.popupTitle == dataTitle){\r\n                  openPopup(popup);\r\n                }\r\n                popup_cross.addEventListener('click', () => {\r\n                  closePopup(popup);\r\n                });\r\n              });\r\n            });\r\n          });\r\n          /* toggle functionality */\r\n          const popup_toggle = document.querySelectorAll('.popup_toggle');\r\n          popup_toggle.forEach(toggle => {\r\n            let recharge_content = toggle.closest('form').querySelector('[data-quick-add-selling-plan-container]');\r\n            toggle.addEventListener('click', () => {\r\n              if(toggle.classList.contains('active')){\r\n                setTimeout(() => {\r\n                  toggle.classList.remove('active');\r\n                  recharge_content.classList.remove('active');\r\n                }, 200);\r\n              } else {\r\n                setTimeout(() => {\r\n                  toggle.classList.add('active');\r\n                  recharge_content.classList.add('active');\r\n                }, 200);\r\n              }\r\n            });\r\n          });\r\n          /* add to cart functionality */\r\n          const popups = document.querySelectorAll('.product_popup');\r\n          popups.forEach(popup => {\r\n            let atc_button = popup.querySelector('.popup_atc');\r\n            let productSelectOptions = popup.querySelector('#productSelect').querySelectorAll('option');\r\n            let selects = popup.querySelectorAll('select[data-variant]');\r\n            let variantId = popup.querySelector('[data-variant-id]');\r\n            let popup_price = popup.querySelector('.product_price');\r\n            let popup_price_original_price = popup.querySelector('.product_price').innerHTML;\r\n            let subscription_toggle = popup.querySelector('.popup_toggle');\r\n\r\n            if(atc_button != null && atc_button != undefined){\r\n              /* update info on select change */\r\n              let product_selects = popup.querySelectorAll('.product_variant');\r\n              product_selects.forEach(select => {\r\n                select.addEventListener('change', () => {\r\n                  let variant_text = findVariant(popup, selects, productSelectOptions, variantId, true);\r\n                  if(variant_text != undefined && variant_text != null){\r\n                    let price = variant_text.split('- ')[1];\r\n                    popup_price.innerHTML = price;\r\n                  } else {\r\n                    popup_price.innerHTML = popup_price_original_price;\r\n                  }\r\n                });\r\n              });\r\n              \r\n              \r\n              atc_button.addEventListener('click', () => {\r\n                elements.popups.forEach(popup => {\r\n                  closePopup(popup);\r\n                });\r\n               /* let quantity = popup.querySelector('input[name='quantity']').getAttribute('value');\r\n                let selling_plan = popup.querySelector('.recharge_select');\r\n                let selling_plan_id = '';\r\n                if(subscription_toggle.classList.contains('active')){\r\n                  selling_plan_id = selling_plan.options[selling_plan.selectedIndex];\r\n                } else {\r\n                  selling_plan_id = undefined;\r\n                }\r\n                addProduct(quantity, findVariant(popup, selects, productSelectOptions, variantId), selling_plan_id); */\r\n              });\r\n              \r\n            }\r\n          });\r\n        }, 1000);\r\n      }\r\n      const addProduct = async (quantity, variantId, sellingPlanId) => {\r\n        try {\r\n          /* selling plan & variant exists */\r\n          if(sellingPlanId != undefined){\r\n            await fetch('/cart/add.js', {\r\n              method: 'POST',\r\n              headers: { 'Content-Type': 'application/json' },\r\n              body: JSON.stringify({\r\n                  id: variantId,\r\n                  quantity: quantity,\r\n                  selling_plan: sellingPlanId.dataset.value\r\n              })\r\n            });\r\n          /* selling plan does not exist */\r\n          } else {\r\n            await fetch('/cart/add.js', {\r\n              method: 'POST',\r\n              headers: { 'Content-Type': 'application/json' },\r\n              body: JSON.stringify({\r\n                  id: variantId,\r\n                  quantity: quantity\r\n              })\r\n            });\r\n          }\r\n          /* variant id does not exist */\r\n          //goCart.fetchAndOpenCart();\r\n          elements.popups.forEach(popup => {\r\n            closePopup(popup);\r\n          });\r\n        } catch(error) {\r\n          console.error(error);\r\n        }\r\n      }\r\n      const findVariant = (selector, selects, productSelectOptions, variantId, returnText) => {\r\n        let select_value = '';\r\n        let productDefaultOption = selector.querySelector('#productSelect');\r\n        let options_array = [];\r\n\r\n        if(selects[0] !== undefined && selects[0] !== null){\r\n          select_value += selects[0].value;\r\n        } \r\n        if(selects[1] !== undefined && selects[1] !== null){\r\n          select_value += ' / ' + selects[1].value;\r\n        }\r\n        if(selects[2] !== undefined && selects[2] !== null){\r\n          select_value += ' / ' + selects[2].value;\r\n        }\r\n        let option_value;\r\n        productSelectOptions.forEach(option => {\r\n          options_array.push(option.text);\r\n          const checker = value => [select_value].some(element => value.includes(element));\r\n          const check_variants_exist = options_array.filter(checker);\r\n          if(option.text.includes(select_value)){\r\n            if(option.text.includes('Sold out')){\r\n              option_value = variantId;\r\n              disableButton(selector.querySelector('.popup_atc'), selector.querySelector('.product_price'));\r\n            } else {\r\n              option_value = option;\r\n              enableButton(selector.querySelector('.popup_atc'), selector.querySelector('.product_price'))\r\n            }\r\n          } else if(check_variants_exist.length === 0){\r\n            option_value = productDefaultOption;\r\n          }\r\n        });\r\n        if(returnText == true){\r\n          return option_value.text;\r\n        } else {\r\n          return option_value.value;\r\n        }\r\n      }\r\n      const disableButton = (button) => {   \r\n        button.classList.add('disabled');\r\n        button.disabled = true;\r\n      }\r\n      const enableButton = (button) => {\r\n        button.classList.remove('disabled');\r\n        button.disabled = false;\r\n      }\r\n      const openPopup = (popup) => {\r\n        popup.classList.add('active');\r\n        elements.html.classList.add('overflow-hidden');\r\n        elements.page_overlay.classList.add('active');\r\n        setTimeout(() => {\r\n          elements.page_overlay.classList.add('show');\r\n        },200);\r\n      };\r\n      const closePopup = (popup) => {\r\n        popup.classList.remove('active');\r\n        elements.html.classList.remove('overflow-hidden');\r\n        elements.page_overlay.classList.remove('show');\r\n        setTimeout(() => {\r\n          elements.page_overlay.classList.remove('active');\r\n        },50);\r\n      }\r\n      return {init};\r\n    })();\r\n\r\n    const flipFunctionality = () => {\r\n      /* this may need revising in the future */\r\n      setTimeout(() => {\r\n        const whats_inside_buttons = document.querySelectorAll('.whats_inside_button');\r\n        whats_inside_buttons.forEach(button => {\r\n          const front_of_tile = button.parentNode.querySelector('.product_flip_front');\r\n          const back_of_tile = button.parentNode.querySelector('.product_flip_back');\r\n          button.addEventListener('click', () => {\r\n            if(front_of_tile.classList.contains('flip')){\r\n              setTimeout(() => {\r\n                button.classList.remove('active');\r\n                front_of_tile.classList.remove('flip');\r\n                back_of_tile.classList.remove('flip');\r\n              }, 200);\r\n            } else {\r\n              setTimeout(() => {\r\n                button.classList.add('active');\r\n                front_of_tile.classList.add('flip');\r\n                back_of_tile.classList.add('flip');\r\n              }, 200);\r\n            }\r\n          });\r\n        });\r\n      }, 1000);\r\n    };\r\n\r\n    function waitForElementToDisplay(selector, callback, checkFrequencyInMs, timeoutInMs) {\r\n      var startTimeInMs = Date.now();\r\n      (function loopSearch() {\r\n          if ((selector) != null) {\r\n            callback();\r\n            return;\r\n          } else {\r\n            setTimeout(function () {\r\n              if (timeoutInMs && Date.now() - startTimeInMs > timeoutInMs)\r\n                return;\r\n              loopSearch();\r\n            }, checkFrequencyInMs);\r\n          }\r\n      })();\r\n    }  \r\n    \r\n\r\n    const glide_products = document.querySelectorAll('.glide__track');\r\n    if(glide_products != undefined && glide_products != null){\r\n      glide_products.forEach(product_slider => {\r\n        setTimeout(() => {\r\n          waitForElementToDisplay(product_slider.querySelectorAll('.glide__slide--clone'), function(){\r\n            popupAtc.init();\r\n            flipFunctionality();\r\n          },1000, 9000);\r\n        }, 1500);\r\n      });\r\n    }\r\n    flipFunctionality();\r\n    popupAtc.init();\r\n  }\r\n};\r\ncustomElements.define('product-tile', ProductTile);\n\n//# sourceURL=webpack://shopify-theme-starter/./src/js/modules/product-tile.js?");

